import * as React from 'react'
import isEmpty from 'lodash/isEmpty'
import isArray from 'lodash/isArray'
import { getFormValues } from '@/registry/lib/form-relate-utils'
import AsyncSelect from '@/registry/components/form-relate-async-select/form-relate-async-select'
import type { RelateFieldProps } from '@/registry/lib/form-relate-types'

/**
 * RelateMultiSelect - 多选关联字段组件
 * 外部工作表关联，多选模式
 */
const RelateMultiSelect: React.FC<RelateFieldProps> = (props) => {
  const { input, field = {}, label, meta, record, disabled: propsDisabled } = props
  const { onChange, value: items } = input || {}
  const { displayField = 'name', schema: relateSchema = {} } = field

  // 获取表单状态用于字段脚本
  const [formState] = React.useState<Record<string, any>>({})

  const disabled = propsDisabled || relateSchema.disabled || false

  // 默认值生效
  React.useEffect(() => {
    const defaultVal = relateSchema?.defaultVal
    setTimeout(() => {
      if (!items && defaultVal && onChange) {
        onChange(defaultVal)
      }
    })
  }, [])

  // 字段脚本部分
  React.useEffect(() => {
    const values = getFormValues(relateSchema, { values: formState })
    if (values && !isEmpty(values)) {
      // TODO: 实现字段脚本逻辑
      // useScriptVal({ schema: relateSchema, value: items, values, record, onChange })
    }
  }, [JSON.stringify(formState)])

  const handleChange = (options: any[]) => {
    if (!options || options.length === 0) {
      onChange?.([])
    } else {
      onChange?.(options.map((opt) => opt.item))
    }
  }

  return (
    <AsyncSelect
      mode="multiple"
      value={
        items && !isEmpty(items) && isArray(items)
          ? items.map((item: any) => ({
              key: item.id,
              label: item[displayField],
              item,
            }))
          : []
      }
      onChange={handleChange}
      field={field}
      label={label}
      disabled={disabled}
      meta={meta}
      record={record}
    />
  )
}

export default RelateMultiSelect

import isEmpty from 'lodash/isEmpty'
import isObject from 'lodash/isObject'
import isArray from 'lodash/isArray'

/**
 * 在 tableSchema 中查找 value?.relate?.id 等于 tableID 的对应 key
 */
export const findRelateKeyInTableSchema = (tableSchema: any, tableID: string): string | null => {
  if (!tableSchema || !tableSchema.properties) {
    return null
  }

  for (const [key, property] of Object.entries(tableSchema.properties)) {
    if ((property as any)?.relate?.id === tableID) {
      return key
    }
  }

  return null
}

/**
 * 在树形数据中查找节点
 */
export const findTreeNode = (treeData: any[], value: any): any => {
  for (const node of treeData) {
    if (node.value === value) {
      return node
    }
    if (node.children && node.children.length > 0) {
      const found = findTreeNode(node.children, value)
      if (found) return found
    }
  }
  return null
}

