/**
 * 简单的 fieldRender 函数
 * 用于在列表中显示字段值
 */
export const fieldRender = (value: any, _schema?: any): React.ReactNode => {
  // 字符串、数字、布尔值直接显示
  if (typeof value === 'string' || typeof value === 'number' || typeof value === 'boolean') {
    return value
  }

  // 对象显示 .name
  if (isObject(value) && !isArray(value)) {
    return (value as any).name ?? (value as any).id ?? JSON.stringify(value)
  }

  // 数组显示 .name join(',')
  if (isArray(value)) {
    return value
      .map(item => {
        if (typeof item === 'string' || typeof item === 'number') {
          return item
        }
        if (isObject(item)) {
          return (item as any).name ?? (item as any).id
        }
        return JSON.stringify(item)
      })
      .filter(Boolean)
      .join(',')
  }

  // 空值处理
  if (isEmpty(value)) {
    return null
  }

  return JSON.stringify(value)
}

/**
 * 获取表单状态 - 用于获取其他字段的值
 * 类似于 use('form') 的功能
 */
export const getFormState = (formState: any, currentFieldKey?: string) => {
  // TODO: 实现表单状态获取逻辑
  // 这个函数应该从 form state 中获取其他字段的值
  // 用于字段联动和脚本计算
  if (!formState) {
    return {}
  }

  const values: Record<string, any> = {}
  for (const key in formState.values) {
    // 跳过当前字段，避免循环依赖
    if (key !== currentFieldKey) {
      values[key] = formState.values[key]
    }
  }

  return { values }
}

/**
 * 获取表单所有值 - 用于字段脚本
 */
export const getFormValues = (schema: any, formState?: any) => {
  if (!formState) {
    return null
  }

  const values: Record<string, any> = {}
  for (const key in formState.values) {
    if (key !== schema.key) {
      values[key] = formState.values[key]
    }
  }

  return values
}

/**
 * Schema 转换器
 * 将关联字段的 schema 转换为组件可用的格式
 */
export const schemaConverter = (
  schema: any,
  options?: { tableSchema?: any }
): {
  type: string
  schema: { name: string }
  fieldSchema?: any
  relateSchema: any
  tableID: string
  displayField: string
  relateTableName: string
  insideFilter?: any
  relateShowFields?: any[]
  selectType?: 'single' | 'multiple'
  key?: string
} | null => {
  if (
    !['object', 'array'].includes(schema.type) ||
    !schema.relate?.id ||
    schema.recordSelectType
  ) {
    return null
  }

  const relate = schema.relate
  const relateShowFields = schema.relateShowFields
  const id = relate.id
  const fieldSchema = relate.fields?.[0]?.fieldSchema

  const result: any = {
    type: schema.selectType === 'multiple' ? 'relate_multi_select' : 'relate_fkselect',
    schema: { name: `core/t/${id}/d` },
    fieldSchema,
    relateSchema: schema,
    tableID: id,
    displayField: relate.fields?.[0]?.key || 'name',
    relateTableName: id,
    insideFilter: schema.insideFilter,
  }

  // 使用 findRelateKeyInTableSchema 查找关联键
  if (options?.tableSchema) {
    const relateKey = findRelateKeyInTableSchema(options.tableSchema, relate.id)
    if (relateKey) {
      result.key = relateKey
    }
  }

  // 多字段
  if (relateShowFields && relateShowFields.length > 0) {
    result.type = 'relate_list_fkselect'
    result.relateShowFields = relateShowFields
    result.selectType = schema.selectType
  }

  return result
}

/**
 * 关联字段相关的类型定义
 */

export interface RelateFieldOption {
  value: string
  label: string
  key?: string
  item?: any
}

export interface RelateFieldProps {
  input: {
    value?: any
    onChange?: (value: any) => void
  }
  field?: {
    schema?: Record<string, any>
    filter?: any
    meta?: any
    key?: string
    displayField?: string
    tableID?: string
    relateShowFields?: Array<{
      key: string
      title: string
      mapToCurrent?: boolean
      mapField?: string
      fieldSchema?: any
    }>
    option?: {
      form?: {
        change: (field: string, value: any) => void
      }
    }
  }
  meta?: any
  record?: any
  antdForm?: any
  label?: string
  disabled?: boolean
}

export interface AsyncSelectProps extends RelateFieldProps {
  value?: {
    key: string
    label: string
    item?: any
  } | null
  mode?: 'multiple' | 'tags'
  isOptionSelected?: (option: RelateFieldOption) => boolean
  style?: React.CSSProperties
}
